import React from 'react'
import { firebase, db } from '../../firebase/config'
import { List} from 'react-native-paper'



const IncomeItems = ({id, type, amount}) => {

    const misc = async () => {
        await db()
        .collection('income')
        .doc(id)
    }

    return (
        <List.Item
        type={type}
        amount={amount}
        onPress={()=>misc()}
        />
    )




}



export default IncomeItems;
